data.content:
MSTest **does not** have `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what you actually use:

| Need | MSTest Approach |
|---|---|
| Greater/less than | `Assert.IsTrue(val > x)` (poor failure messages) |
| Equality | `Assert.AreEqual(expected, actual)` |
| Tolerance | `Assert.AreEqual(expected, actual, delta)` |
| Exceptions | `Assert.ThrowsException<T>(action)` |

For richer comparisons, pair with **FluentAssertions** (`value.Should().BeInRange(lo, hi)`).

Here's a complete test class using what MSTest provides:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──────────────────────────────────

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        double result = _calc.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result, 0.001); // delta for floating-point tolerance
    }

    [TestMethod]
    public void CalculatePercentage_TotalIsZero_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundary tests ──────────────────────────────

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0, "A")]   // boundary: exactly 90
    [DataRow(89.999, "B")] // just below A
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(
        double percentage, string expectedGrade)
    {
        string grade = _calc.GetGrade(percentage);
        Assert.AreEqual(expectedGrade, grade);
    }

    // ── NormalizeScore ────────────────────────────────────────

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        double result = _calc.NormalizeScore(50, 100);
        Assert.AreEqual(50.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        double result = _calc.NormalizeScore(150, 100);
        // No Assert.IsLessThanOrEqual — use Assert.IsTrue or Assert.AreEqual
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_Zero_ReturnsZero()
    {
        Assert.AreEqual(0.0, _calc.NormalizeScore(0, 100), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}
```

**Key takeaways:**

- **`Assert.AreEqual(expected, actual, delta)`** — the `double` overload with a `delta` (3rd arg) is your main tool for numeric boundary checks with floating-point tolerance
- **`Assert.ThrowsException<T>`** — for validating guard clauses
- **`DataRow`** — great for testing grade boundaries systematically
- MSTest has no range/comparison assertions — use `Assert.IsTrue()` as a fallback, but prefer exact `AreEqual` with delta when possible since it gives better failure messages (shows expected vs actual)
